from collections import OrderedDict

def solve(capacity: int, ops: list[str]) -> list[int]:
    result = []
    cache = OrderedDict()

    for op in ops:
        parts = op.split()
        if parts[0] == "put":
            if capacity == 0:
                continue
            key = int(parts[1])
            value = int(parts[2])
            if key in cache:
                cache.move_to_end(key)
                cache[key] = value
            else:
                if len(cache) >= capacity:
                    cache.popitem(last=False)
                cache[key] = value
        elif parts[0] == "get":
            if capacity == 0:
                result.append(-1)
                continue
            key = int(parts[1])
            if key in cache:
                cache.move_to_end(key)
                result.append(cache[key])
            else:
                result.append(-1)

    return result
