import re

def solve(text: str) -> int:
    total = 0
    pattern = re.compile(r'(\d+)\s*(ms|[dhms])')
    for match in pattern.finditer(text):
        value = int(match.group(1))
        unit = match.group(2)
        if unit == 'd':
            total += value * 86400000
        elif unit == 'h':
            total += value * 3600000
        elif unit == 'm':
            total += value * 60000
        elif unit == 's':
            total += value * 1000
        elif unit == 'ms':
            total += value
    return total
```

