def solve(s: str) -> bool:
    stack = []
    in_string = False
    quote_char = None
    i = 0
    n = len(s)
    while i < n:
        c = s[i]
        if in_string:
            if c == '\\':
                i += 2
                continue
            elif c == quote_char:
                in_string = False
                quote_char = None
        else:
            if c == "'" or c == '"':
                in_string = True
                quote_char = c
            elif c in '([{':
                stack.append(c)
            elif c in ')]}':
                if not stack:
                    return False
                top = stack.pop()
                if (c == ')' and top != '(') or \
                   (c == ']' and top != '[') or \
                   (c == '}' and top != '{'):
                    return False
        i += 1
    return len(stack) == 0
```

